/**
 * Background Script for Chrome Extension
 *
 * This script initializes the Chrome extension, listens for events, and handles background tasks
 * such as authentication, message passing, and user preferences storage.
 *
 * Handles:
 * - Extension installation event
 * - Message listeners for handling user authentication, preferences, and Canvas API token retrieval.
 *
 * Documentation generated by ChatGPT
 */

import { authenticateUser } from "./scripts/identity-script.js";
import { getAssignments, getCourses, getCanvasPAT } from "./scripts/canvas-script.js";
import { openSidePanel } from "./scripts/sidepanel.js";
import { getGoogleToken, syncCalendar, getCalendarID, getOrCreateCalendar, gatherEvents, checkCalendarExists, importGoogleCalendarEvents } from "./scripts/GoogleCalendar.js";
import { alarmInstall, storageListener, chromeStartUpListener, dailyAlarmListener, onClickNotification} from "./scripts/notifications.js";

const PAGES_BRIDGE_SYNC_KEYS = [
  "user",
  "preferences",
  "backgroundColor",
  "textColor",
  "selectedThemeKey",
  "involvedClubs",
  "selectedInterests",
  "selectedSports",
];

const PAGES_BRIDGE_LOCAL_KEYS = ["userEvents", "Canvas_Assignments", "filteredIC", "savedUNLVEvents", "googleCalendarEvents", "colorList"];

function parseAssignmentDate(value) {
  if (!value) {
    return null;
  }

  const parsed = new Date(value);
  if (!Number.isNaN(parsed.getTime())) {
    return parsed;
  }

  const normalized = new Date(String(value).replace(",", ""));
  if (!Number.isNaN(normalized.getTime())) {
    return normalized;
  }

  return null;
}

function parseUserEventDateTime(event) {
  if (!event?.startDate) {
    return null;
  }

  const [year, month, day] = event.startDate.split("-").map(Number);
  if (!year || !month || !day) {
    return null;
  }

  const parsed = new Date(year, month - 1, day);

  if (!event.allDay && event.startTime) {
    const [hours, minutes] = event.startTime.split(":").map(Number);
    parsed.setHours(hours || 0, minutes || 0, 0, 0);
  } else {
    parsed.setHours(0, 0, 0, 0);
  }

  return Number.isNaN(parsed.getTime()) ? null : parsed;
}

function parseInvolvementCenterDateTime(event) {
  if (!event?.startDate) {
    return null;
  }

  const parsed = new Date(`${event.startDate} ${event.startTime || "12:00 AM"}`);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
}

function parseSavedCampusEventDateTime(event) {
  if (!event?.startDate) {
    return null;
  }

  if (!event.startTime || event.startTime === "(ALL DAY)") {
    return new Date(`${event.startDate}T00:00:00`);
  }

  const parsed = new Date(`${event.startDate} ${event.startTime}`);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
}

function parseGoogleCalendarEventDateTime(event) {
  if (!event?.startDate) {
    return null;
  }

  if (!event.startTime || event.startTime === "(ALL DAY)") {
    return new Date(`${event.startDate}T00:00:00`);
  }

  const parsed = new Date(`${event.startDate}T${event.startTime}`);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
}

function toBridgeDate(parsedDate) {
  if (!(parsedDate instanceof Date) || Number.isNaN(parsedDate.getTime())) {
    return "";
  }

  const year = parsedDate.getFullYear();
  const month = String(parsedDate.getMonth() + 1).padStart(2, "0");
  const day = String(parsedDate.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

function toBridgeTime(parsedDate) {
  if (!(parsedDate instanceof Date) || Number.isNaN(parsedDate.getTime())) {
    return "";
  }

  return parsedDate.toLocaleTimeString("en-US", {
    hour: "numeric",
    minute: "2-digit",
    hour12: true,
  });
}

function getSavedEventSourceLabel(event) {
  if (event?.sport) {
    return "Rebel Sports";
  }

  if (event?.category) {
    return "UNLV Calendar";
  }

  return "Saved Campus Event";
}

function buildBridgeCalendarEvents(localData) {
  const canvasEvents = Array.isArray(localData.Canvas_Assignments)
    ? localData.Canvas_Assignments
        .flatMap((assignment) => {
          const dueAt = parseAssignmentDate(assignment?.due_at);
          if (!dueAt) {
            return [];
          }

          return [{
            id: `canvas-${assignment.id}`,
            title: assignment.title || "Untitled Assignment",
            startDate: toBridgeDate(dueAt),
            endDate: toBridgeDate(dueAt),
            startTime: toBridgeTime(dueAt),
            endTime: toBridgeTime(dueAt),
            allDay: false,
            location: "",
            description: assignment.context_name || "",
            link: assignment.html_url || "",
            sourceLabel: "Canvas",
            eventType: "canvasAssignment",
            courseID: assignment.course_id || null,
            calendarKey: "extensionEvents",
          }];
        })
    : [];

  const userEvents = Array.isArray(localData.userEvents)
    ? localData.userEvents.map((event, index) => ({
        id: `user-${event.title || "event"}-${event.startDate || index}-${index}`,
        title: event.title || "Custom Event",
        startDate: event.startDate || "",
        endDate: event.endDate || event.startDate || "",
        startTime: event.allDay ? "(ALL DAY)" : (event.startTime || ""),
        endTime: event.allDay ? "(ALL DAY)" : (event.endTime || event.startTime || ""),
        allDay: Boolean(event.allDay),
        location: event.location || "",
        description: event.desc || "",
        link: "",
        sourceLabel: "Your Events",
        eventType: "userEvents",
        calendarKey: "extensionEvents",
      }))
    : [];

  const involvementCenterEvents = Array.isArray(localData.filteredIC)
    ? localData.filteredIC.map((event, index) => ({
        id: `ic-${event.name || "event"}-${event.startDate || index}-${index}`,
        title: event.name || "Involvement Center Event",
        startDate: event.startDate || "",
        endDate: event.endDate || event.startDate || "",
        startTime: event.startTime || "",
        endTime: event.endTime || event.startTime || "",
        allDay: event.startTime === "(ALL DAY)",
        location: event.location || "",
        description: event.organization ? `RSO: ${event.organization}` : "",
        link: event.link || "",
        sourceLabel: "Involvement Center",
        eventType: "InvolvementCenter",
        calendarKey: "extensionEvents",
      }))
    : [];

  const savedCampusEvents = Array.isArray(localData.savedUNLVEvents)
    ? localData.savedUNLVEvents.map((event, index) => ({
        id: `saved-${event.name || "event"}-${event.startDate || index}-${index}`,
        title: event.name || "Saved Campus Event",
        startDate: event.startDate || "",
        endDate: event.endDate || event.startDate || "",
        startTime: event.startTime || "",
        endTime: event.endTime || event.startTime || "",
        allDay: event.startTime === "(ALL DAY)",
        location: event.location || "",
        description: event.organization || event.category || event.sport || "",
        link: event.link || "",
        sourceLabel: getSavedEventSourceLabel(event),
        eventType: "UNLVEvents",
        calendarKey: "extensionEvents",
      }))
    : [];
  const googleCalendarEvents = Array.isArray(localData.googleCalendarEvents)
    ? localData.googleCalendarEvents.map((event, index) => ({
        id: `google-${event.googleEventId || event.title || index}-${index}`,
        title: event.title || "Google Calendar Event",
        startDate: event.startDate || "",
        endDate: event.endDate || event.startDate || "",
        startTime: event.allDay ? "(ALL DAY)" : (event.startTime || ""),
        endTime: event.allDay ? "(ALL DAY)" : (event.endTime || event.startTime || ""),
        allDay: Boolean(event.allDay),
        location: event.location || "",
        description: event.desc || "",
        link: event.link || "",
        sourceLabel: "Google Calendar",
        eventType: "googleCalendar",
        calendarKey: "extensionEvents",
      }))
    : [];

  return [...canvasEvents, ...userEvents, ...involvementCenterEvents, ...savedCampusEvents, ...googleCalendarEvents];
}

function buildPagesBridgePayload(syncData, localData) {
  const now = new Date();
  const bridgeCalendarEvents = buildBridgeCalendarEvents(localData);
  const upcomingAssignments = Array.isArray(localData.Canvas_Assignments)
    ? localData.Canvas_Assignments
        .map((assignment) => ({
          ...assignment,
          parsedDueAt: parseAssignmentDate(assignment?.due_at),
        }))
        .filter((assignment) => assignment.parsedDueAt)
        .filter((assignment) => assignment.parsedDueAt >= now)
        .sort((left, right) => left.parsedDueAt - right.parsedDueAt)
        .slice(0, 4)
        .map((assignment) => ({
          id: assignment.id,
          title: assignment.title || "Untitled Assignment",
          courseName: assignment.context_name || "",
          dueAt: assignment.due_at,
          link: assignment.html_url || "",
        }))
    : [];
  const upcomingAssignmentCount = Array.isArray(localData.Canvas_Assignments)
    ? localData.Canvas_Assignments
        .map((assignment) => parseAssignmentDate(assignment?.due_at))
        .filter((dueAt) => dueAt && dueAt >= now)
        .length
    : 0;
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const upcomingUserEvents = Array.isArray(localData.userEvents)
    ? localData.userEvents
        .map((event) => ({
          ...event,
          parsedStart: parseUserEventDateTime(event),
        }))
        .filter((event) => event.parsedStart && event.parsedStart >= today)
        .sort((left, right) => left.parsedStart - right.parsedStart)
        .map(({ parsedStart, ...event }) => event)
    : [];
  const upcomingICEvents = Array.isArray(localData.filteredIC)
    ? localData.filteredIC
        .map((event) => ({
          ...event,
          parsedStart: parseInvolvementCenterDateTime(event),
        }))
        .filter((event) => event.parsedStart && event.parsedStart >= today)
        .sort((left, right) => left.parsedStart - right.parsedStart)
        .map(({ parsedStart, ...event }) => event)
    : [];
  const upcomingSavedCampusEvents = Array.isArray(localData.savedUNLVEvents)
    ? localData.savedUNLVEvents
        .map((event) => ({
          ...event,
          parsedStart: parseSavedCampusEventDateTime(event),
        }))
        .filter((event) => event.parsedStart && event.parsedStart >= today)
        .sort((left, right) => left.parsedStart - right.parsedStart)
        .map(({ parsedStart, ...event }) => event)
    : [];
  const upcomingGoogleCalendarEvents = Array.isArray(localData.googleCalendarEvents)
    ? localData.googleCalendarEvents
        .map((event) => ({
          ...event,
          parsedStart: parseGoogleCalendarEventDateTime(event),
        }))
        .filter((event) => event.parsedStart && event.parsedStart >= today)
        .sort((left, right) => left.parsedStart - right.parsedStart)
        .map(({ parsedStart, ...event }) => event)
    : [];

  const user = syncData.user
    ? {
        name: syncData.user.name || "",
        email: syncData.user.email || "",
        picture: syncData.user.picture || "",
      }
    : null;

  return {
    user,
    preferences: syncData.preferences || {},
    theme: {
      backgroundColor: syncData.backgroundColor || "#BB0000",
      textColor: syncData.textColor || "#d3d3d3",
      selectedThemeKey: syncData.selectedThemeKey || "custom",
    },
    involvedClubs: Array.isArray(syncData.involvedClubs) ? syncData.involvedClubs : [],
    selectedInterests: Array.isArray(syncData.selectedInterests) ? syncData.selectedInterests : [],
    selectedSports: Array.isArray(syncData.selectedSports) ? syncData.selectedSports : [],
    userEventCount: upcomingUserEvents.length + upcomingICEvents.length + upcomingSavedCampusEvents.length + upcomingGoogleCalendarEvents.length,
    userEvents: upcomingUserEvents,
    involvementCenterEvents: upcomingICEvents,
    savedUNLVEvents: upcomingSavedCampusEvents,
    googleCalendarEvents: upcomingGoogleCalendarEvents,
    assignmentCount: Array.isArray(localData.Canvas_Assignments) ? localData.Canvas_Assignments.length : 0,
    upcomingAssignmentCount,
    upcomingAssignments,
    colorList: localData.colorList || null,
    calendarEvents: bridgeCalendarEvents,
    syncedAt: new Date().toISOString(),
  };
}

function getPagesBridgeState(sendResponse) {
  chrome.storage.sync.get(PAGES_BRIDGE_SYNC_KEYS, (syncData) => {
    chrome.storage.local.get(PAGES_BRIDGE_LOCAL_KEYS, (localData) => {
      sendResponse({
        success: true,
        payload: buildPagesBridgePayload(syncData, localData),
      });
    });
  });
}

/**
* Listens for and handles any Chrome alarms.
*/
chrome.alarms.onAlarm.addListener((alarm) => {
  if (alarm.name == "getAssignments") { // alarm is triggered, update storage with new assignments
    updateAssignments();
  }
});

